package ru.memearena.security; import com.fasterxml.jackson.databind.ObjectMapper; import jakarta.servlet.http.*; import org.springframework.http.*; import org.springframework.security.core.AuthenticationException; import org.springframework.security.web.AuthenticationEntryPoint; import org.springframework.stereotype.Component; import ru.memearena.error.*; import java.io.IOException; import java.time.*; import java.util.*; @Component public class RestAuthenticationEntryPoint implements AuthenticationEntryPoint{private final ObjectMapper mapper; private final Clock clock; public RestAuthenticationEntryPoint(ObjectMapper mapper,Clock clock){this.mapper=mapper;this.clock=clock;} public void commence(HttpServletRequest req,HttpServletResponse res,AuthenticationException e)throws IOException{res.setStatus(401);res.setContentType("application/json");mapper.writeValue(res.getOutputStream(),new ApiError(ErrorCode.AUTHENTICATION_REQUIRED.name(),"Authentication required",Instant.now(clock),req.getRequestURI(),List.of()));}}
